    ap_sync_reg_entry_proc_U0_ap_ready_assign_proc : process(ap_clk)
    begin
        if (ap_clk'event and ap_clk =  '1') then
            if (ap_rst_n_inv = '1') then
                ap_sync_reg_entry_proc_U0_ap_ready <= ap_const_logic_0;
            else
                if (((ap_sync_ready and ap_start) = ap_const_logic_1)) then 
                    ap_sync_reg_entry_proc_U0_ap_ready <= ap_const_logic_0;
                else 
                    ap_sync_reg_entry_proc_U0_ap_ready <= ap_sync_entry_proc_U0_ap_ready;
                end if; 
            end if;
        end if;
    end process;


    ap_sync_reg_scrambler_U0_ap_ready_assign_proc : process(ap_clk)
    begin
        if (ap_clk'event and ap_clk =  '1') then
            if (ap_rst_n_inv = '1') then
                ap_sync_reg_scrambler_U0_ap_ready <= ap_const_logic_0;
            else
                if (((ap_sync_ready and ap_start) = ap_const_logic_1)) then 
                    ap_sync_reg_scrambler_U0_ap_ready <= ap_const_logic_0;
                else 
                    ap_sync_reg_scrambler_U0_ap_ready <= ap_sync_scrambler_U0_ap_ready;
                end if; 
            end if;
        end if;
    end process;

    ap_done <= interleaver_U0_ap_done;
    ap_idle <= (scrambler_U0_ap_idle and interleaver_U0_ap_idle and entry_proc_U0_ap_idle and conv_enc_U0_ap_idle);
    ap_ready <= ap_sync_ready;

    ap_rst_n_inv_assign_proc : process(ap_rst_n)
    begin
                ap_rst_n_inv <= not(ap_rst_n);
    end process;

    ap_sync_entry_proc_U0_ap_ready <= (entry_proc_U0_ap_ready or ap_sync_reg_entry_proc_U0_ap_ready);
    ap_sync_ready <= (ap_sync_scrambler_U0_ap_ready and ap_sync_entry_proc_U0_ap_ready);
    ap_sync_scrambler_U0_ap_ready <= (scrambler_U0_ap_ready or ap_sync_reg_scrambler_U0_ap_ready);
    conv_enc_U0_ap_continue <= ap_const_logic_1;
    conv_enc_U0_ap_start <= start_for_conv_enc_U0_empty_n;
    data_in_TREADY <= scrambler_U0_data_in_TREADY;
    data_out_TDATA <= interleaver_U0_data_out_TDATA;
    data_out_TVALID <= interleaver_U0_data_out_TVALID;
    entry_proc_U0_ap_continue <= ap_const_logic_1;
    entry_proc_U0_ap_start <= ((ap_sync_reg_entry_proc_U0_ap_ready xor ap_const_logic_1) and ap_start and ap_const_logic_1);
    entry_proc_U0_start_full_n <= (start_for_interleaver_U0_full_n and start_for_conv_enc_U0_full_n);
    interleaver_U0_ap_continue <= ap_const_logic_1;
    interleaver_U0_ap_start <= start_for_interleaver_U0_empty_n;
    scrambler_U0_ap_continue <= ap_const_logic_1;
    scrambler_U0_ap_start <= ((ap_sync_reg_scrambler_U0_ap_ready xor ap_const_logic_1) and ap_start and ap_const_logic_1);
    start_for_conv_enc_U0_din <= (0=>ap_const_logic_1, others=>'-');
    start_for_interleaver_U0_din <= (0=>ap_const_logic_1, others=>'-');
end behav;
